using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Provides utility methods for creating in-memory DbContext instances
/// and draining the static notification queue between tests.
/// </summary>
public static class TestDbContextHelper
{
    /// <summary>
    /// Creates a SchoolContext backed by an in-memory database with a unique name.
    /// Each call returns a context with an isolated database instance.
    /// </summary>
    public static SchoolContext CreateInMemoryContext()
    {
        return CreateInMemoryContext(Guid.NewGuid().ToString());
    }

    /// <summary>
    /// Creates a SchoolContext backed by an in-memory database with the specified name.
    /// Use a shared name when you need two context instances pointing at the same data
    /// (e.g., seed with one, test with another to avoid EF Core tracking conflicts).
    /// </summary>
    public static SchoolContext CreateInMemoryContext(string databaseName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains all pending notifications from the static ConcurrentQueue
    /// used by NotificationService. Call this in TestInitialize to ensure
    /// a clean queue state for notification-related tests.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        service.Dispose();
    }
}

