using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Services;

[TestClass]
[DoNotParallelize] // Static ConcurrentQueue is shared across all instances
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from other tests
        TestDbContextHelper.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithEntityTypeAndId_CanBeReceived()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsFalse(notification.IsRead);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Doe"),
            $"Expected message to contain 'John Doe', but was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 101"),
            $"Expected message to contain 'ID: 101', but was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithUserName_UsesProvidedUserName()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "AdminUser");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("AdminUser", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "Alice Smith", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student 'Alice Smith' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateWithoutDisplayName_GeneratesIdBasedMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Instructor", "7", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Instructor (ID: 7) has been created", notification.Message);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_FIFO_Order()
    {
        // Arrange
        _sut.SendNotification("First", "1", EntityOperation.CREATE);
        _sut.SendNotification("Second", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Third", "3", EntityOperation.DELETE);

        // Act & Assert - should come out in FIFO order
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("First", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("Second", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("Third", third.EntityType);

        // Queue should now be empty
        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        _sut.Dispose();
        // Should be safe to call multiple times
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToApproximateNow()
    {
        // Arrange
        var beforeSend = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var afterSend = DateTime.Now;

        var notification = _sut.ReceiveNotification();

        // Assert - CreatedAt should be between beforeSend and afterSend
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= beforeSend.AddSeconds(-1),
            $"CreatedAt {notification.CreatedAt} should be >= {beforeSend.AddSeconds(-1)}");
        Assert.IsTrue(notification.CreatedAt <= afterSend.AddSeconds(1),
            $"CreatedAt {notification.CreatedAt} should be <= {afterSend.AddSeconds(1)}");
    }
}

using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages_CeilDivision()
    {
        // Arrange & Act - 10 items, 3 per page → ceil(10/3) = 4
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 20, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    [DataRow(5, 1, 5, 1, DisplayName = "5 items, 5 per page = 1 page")]
    [DataRow(6, 1, 5, 2, DisplayName = "6 items, 5 per page = 2 pages")]
    [DataRow(1, 1, 10, 1, DisplayName = "1 item, 10 per page = 1 page")]
    [DataRow(0, 1, 10, 0, DisplayName = "0 items, 10 per page = 0 pages")]
    [DataRow(100, 1, 10, 10, DisplayName = "100 items, 10 per page = 10 pages")]
    public void TotalPages_CalculatedCorrectly(int totalCount, int pageIndex, int pageSize, int expectedPages)
    {
        // Act
        var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedPages, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange - 10 items, 5 per page = 2 pages, on page 2
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // Arrange - 10 items, 5 per page = 2 pages, on page 1
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void Create_FromQueryable_ReturnsPaginatedList()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act - page 2, 5 per page
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // ceil(20/5) = 4
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);  // Skip(5).Take(5) → 6,7,8,9,10
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act - page 1, 5 per page
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act - page 3, 5 per page → only 2 items remain
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }
}

using System;
