        // Assert
        Assert.AreEqual("Smith, John", fullName);
    }

    [TestMethod]
    public void Instructor_FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var instructor = new Instructor { LastName = "Abercrombie", FirstMidName = "Kim" };

        // Act & Assert
        Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange
        var date = new DateTime(2020, 9, 1);
