        var instructor = new Instructor { HireDate = date };

        // Assert
        Assert.AreEqual(date, instructor.HireDate);
    }

    // ========== ErrorViewModel ==========

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_WhenSet_ReturnsTrue()
    {
        // Arrange
