        // Assert
        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_WhenNull_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = null };

        // Assert
        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_WhenEmpty_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = "" };

        // Assert
        Assert.IsFalse(model.ShowRequestId);
    }

