    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Instructor SeedInstructor(string lastName = "Smith", string firstName = "John")
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private (Department Dept, Course Course) SeedDeptAndCourse(string deptName = "Math", string courseTitle = "Calculus", int courseId = 1001)
    {
        var dept = new Department { Name = deptName, Budget = 100000m, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = courseId, Title = courseTitle, Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        return (dept, course);
    }

    // ========== Index ==========

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithInstructors()
    {
        // Arrange
        SeedInstructor("Anderson", "Alice");
        SeedInstructor("Baker", "Bob");

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
        // Ordered by LastName
        Assert.AreEqual("Anderson", model.Instructors.First().LastName);
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsAssignedCourses()
    {
        // Arrange
        var (dept, course) = SeedDeptAndCourse();
        var instructor = SeedInstructor("Prof", "Test");

        // Add course assignment
        var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        _context.CourseAssignments.Add(ca);
        _context.SaveChanges();

        // Need to reload with navigation props using a new context
        var dbName = _context.Database.GetDbConnection().Database;
        _controller.Dispose();
        _context.Dispose();
        _context = TestDbContextHelper.CreateInMemoryContext(dbName);
        _controller = new InstructorsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), Mock.Of<ITempDataProvider>());

        // Act
        var result = _controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Calculus", model.Courses.First().Title);
    }

