    [TestMethod]
    public void DeleteConfirmed_InstructorIsDepartmentAdmin_NullifiesAdminReference()
    {
        // Arrange
        var instructor = SeedInstructor("AdminProf", "Jane");
        var dept = new Department
        {
            Name = "CS",
            Budget = 200000m,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);

        // Department should have InstructorID set to null
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept.InstructorID);
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorNotAdmin_DepartmentUnaffected()
    {
        // Arrange
        var admin = SeedInstructor("Admin", "Stay");
        var toDelete = SeedInstructor("Delete", "Me");

        var dept = new Department
        {
            Name = "CS",
            Budget = 200000m,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = admin.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act - delete the non-admin instructor
        var result = _controller.DeleteConfirmed(toDelete.ID);

        // Assert
        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);

        // Department admin should remain unchanged
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.AreEqual(admin.ID, updatedDept.InstructorID);
    }
