using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedEnrollmentData()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "Alice", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.Students.Add(new Student { LastName = "B", FirstMidName = "Bob", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.Students.Add(new Student { LastName = "C", FirstMidName = "Charlie", EnrollmentDate = new DateTime(2021, 9, 1) });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // Two distinct enrollment dates

        var group2020 = model.Single(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
        Assert.AreEqual(2, group2020.StudentCount);

        var group2021 = model.Single(g => g.EnrollmentDate == new DateTime(2021, 9, 1));
        Assert.AreEqual(1, group2021.StudentCount);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", result.ViewData["Message"]);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
