using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
[DoNotParallelize] // NotificationService uses a static queue
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), Mock.Of<ITempDataProvider>());

        // Drain any leftover notifications from other tests
        TestDbContextHelper.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        // Check "success" and "count" properties via reflection (anonymous type)
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.IsTrue((bool)successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, (int)countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotificationList()
    {
        // Arrange - add notifications via the notification service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsTrue((bool)successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, (int)countProp.GetValue(value));

        var notificationsProp = value.GetType().GetProperty("notifications");
        var notifications = notificationsProp.GetValue(value) as List<Notification>;
        Assert.IsNotNull(notifications);
        Assert.AreEqual(2, notifications.Count);
        Assert.AreEqual("Student", notifications[0].EntityType);
        Assert.AreEqual("Course", notifications[1].EntityType);

        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_CapsAt10()
    {
        // Arrange - add 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, (int)countProp.GetValue(value));

        service.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.IsTrue((bool)successProp.GetValue(value));
    }
}

