+using System.Collections.Generic;
+using System.Linq;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using ContosoUniversity;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndex()
+    {
+        // Arrange & Act
+        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);
+
+        // Assert
+        Assert.AreEqual(3, list.PageIndex);
+    }
+
+    [TestMethod]
+    public void Constructor_SetsTotalPages_CeilDivision()
+    {
+        // Arrange & Act - 10 items, 3 per page → ceil(10/3) = 4
+        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);
+
+        // Assert
+        Assert.AreEqual(4, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_AddsItemsToList()
+    {
+        // Arrange
+        var items = new List<string> { "alpha", "beta", "gamma" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 20, 1, 10);
+
+        // Assert
+        Assert.AreEqual(3, list.Count);
+        Assert.AreEqual("alpha", list[0]);
+        Assert.AreEqual("beta", list[1]);
+        Assert.AreEqual("gamma", list[2]);
+    }
+
+    [TestMethod]
+    [DataRow(5, 1, 5, 1, DisplayName = "5 items, 5 per page = 1 page")]
+    [DataRow(6, 1, 5, 2, DisplayName = "6 items, 5 per page = 2 pages")]
+    [DataRow(1, 1, 10, 1, DisplayName = "1 item, 10 per page = 1 page")]
+    [DataRow(0, 1, 10, 0, DisplayName = "0 items, 10 per page = 0 pages")]
+    [DataRow(100, 1, 10, 10, DisplayName = "100 items, 10 per page = 10 pages")]
+    public void TotalPages_CalculatedCorrectly(int totalCount, int pageIndex, int pageSize, int expectedPages)
+    {
+        // Act
+        var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);
+
+        // Assert
+        Assert.AreEqual(expectedPages, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_FirstPage_ReturnsFalse()
+    {
+        // Arrange
+        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
+
+        // Assert
+        Assert.IsFalse(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_SecondPage_ReturnsTrue()
+    {
+        // Arrange
+        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);
+
+        // Assert
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_LastPage_ReturnsFalse()
+    {
+        // Arrange - 10 items, 5 per page = 2 pages, on page 2
+        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+
+        // Assert
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_NotLastPage_ReturnsTrue()
+    {
+        // Arrange - 10 items, 5 per page = 2 pages, on page 1
+        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+
+        // Assert
+        Assert.IsTrue(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_FromQueryable_ReturnsPaginatedList()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 20).AsQueryable();
+
+        // Act - page 2, 5 per page
+        var result = PaginatedList<int>.Create(source, 2, 5);
+
+        // Assert
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages); // ceil(20/5) = 4
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(6, result[0]);  // Skip(5).Take(5) → 6,7,8,9,10
+        Assert.AreEqual(10, result[4]);
+    }
+
+    [TestMethod]
+    public void Create_FirstPage_ReturnsFirstItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 15).AsQueryable();
+
+        // Act - page 1, 5 per page
+        var result = PaginatedList<int>.Create(source, 1, 5);
+
+        // Assert
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.AreEqual(3, result.TotalPages);
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(1, result[0]);
+        Assert.AreEqual(5, result[4]);
+    }
+
+    [TestMethod]
+    public void Create_LastPage_ReturnsRemainingItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 12).AsQueryable();
+
+        // Act - page 3, 5 per page → only 2 items remain
+        var result = PaginatedList<int>.Create(source, 3, 5);
+
+        // Assert
+        Assert.AreEqual(3, result.PageIndex);
+        Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
+        Assert.AreEqual(2, result.Count);
+        Assert.AreEqual(11, result[0]);
+        Assert.AreEqual(12, result[1]);
+    }
+}
+

