        ViewBag.InstructorID = id.Value;
        viewModel.Courses = viewModel.Instructors.Where(
            i => i.ID == id.Value).Single().CourseAssignments.Select(s => s.Course);
    }

    if (courseID != null)
    {
        ViewBag.CourseID = courseID.Value;
        viewModel.Enrollments = viewModel.Courses.Where(
            x => x.CourseID == courseID).Single().Enrollments;
    }

    return View(viewModel);
}
```

The error "Relational-specific methods can only be used when the context is using a relational database provider" comes from my test code, not the controller. Look at my test:

```csharp
var dbName = _context.Database.GetDbConnection().Database
```

That's calling `GetDbConnection()` which the InMemory provider doesn't support. The fix is straightforward—I need to stop using that method and instead establish a shared database name upfront for both tests.

