            CourseAssignments = new List<CourseAssignment>()
        };
        seedContext.Instructors.Add(instructor);
        seedContext.SaveChanges();
        instructorId = instructor.ID;

        seedContext.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });
        seedContext.SaveChanges();
    }

    // Use a fresh context for the test to ensure navigation properties are loaded via Include
    using var testContext = TestDbContextHelper.CreateInMemoryContext(dbName);
    using var controller = new InstructorsController(testContext);
    controller.TempData = new TempDataDictionary(new DefaultHttpContext(), Mock.Of<ITempDataProvider>());

    // Act
    var result = controller.Index(instructorId, null) as ViewResult;

    // Assert
    Assert.IsNotNull(result);
